t.script:
                (function() {
                    var gameId = ;
                    var csrfToken = '';
                    var input = document.getElementById('barcode-input');
                    var resultDiv = document.getElementById('result');
                    var counterDiv = document.getElementById('counter');

                    function doScan(barcode) {
                        if (!barcode || !barcode.trim()) return;
                        fetch('/yadouda/scan', {
                            method: 'POST',
                            headers: {
                                'Content-Type': 'application/json',
                                'X-CSRF-TOKEN': csrfToken
                            },
                            body: JSON.stringify({
                                jsonrpc: '2.0',
                                method: 'call',
                                params: { game_id: gameId, ticket_code: barcode.trim() },
                                id: 1
                            })
                        }).then(function(r) { return r.json(); }).then(function(data) {
                            var res = data.result || data;
                            if (res.status === 'success') {
                                resultDiv.innerHTML = '
' + (res.message || 'OK') + '';
                                counterDiv.textContent = "Today's total: " + (res.game_total || 0);
                                input.value = '';
                            } else {
                                resultDiv.innerHTML = '
' + (res.message || 'Error') + '';
                            }
                            input.focus();
                        }).catch(function(err) {
                            resultDiv.innerHTML = '
Network error';
                            input.focus();
                        });
                    }

                    input.addEventListener('keypress', function(e) {
                        if (e.which === 13) {
                            e.preventDefault();
                            doScan(input.value);
                        }
                    });
                    input.focus();
                })();
